/* ------------------------------------- helpers ------------------------------------- */

function resizeImageFile(file, maxDim = 1100) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new window.Image();
      img.onload = () => {
        let { width, height } = img;
        if (width > maxDim || height > maxDim) {
          if (width > height) { height = Math.round((height * maxDim) / width); width = maxDim; }
          else { width = Math.round((width * maxDim) / height); height = maxDim; }
        }
        const canvas = document.createElement("canvas");
        canvas.width = width; canvas.height = height;
        const ctx = canvas.getContext("2d");
        ctx.drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL("image/jpeg", 0.72));
      };
      img.onerror = reject;
      img.src = e.target.result;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

function useDebouncedSave(data, onError) {
  const timer = useRef(null);
  useEffect(() => {
    if (!data) return;
    if (timer.current) clearTimeout(timer.current);
    timer.current = setTimeout(async () => {
      try {
        const res = await window.storage.set(STORAGE_KEY, JSON.stringify(data), false);
        if (!res) onError?.(true); else onError?.(false);
      } catch (e) {
        console.error("save failed", e);
        onError?.(true);
      }
    }, 600);
    return () => clearTimeout(timer.current);
  }, [data]);
}

function calcProgress(org, venues) {
  const checks = [
    org.schoolName, org.address, org.mascot, org.colors,
    org.leadName, org.leadRole, org.leadPhone, org.leadEmail, org.commMethod,
    org.aedLocations,
  ];
  let total = checks.length;
  let done = checks.filter(Boolean).length;

  venues.forEach((v) => {
    const need = [v.name, v.sports, v.address, v.gatesLocked, v.weatherSafe];
    if (v.gatesLocked === "yes") need.push(v.gateLocations, v.gateKey);
    total += need.length;
    done += need.filter(Boolean).length;
  });

  return { done, total: Math.max(total, 1), pct: Math.round((done / Math.max(total, 1)) * 100) };
}

function escapeHtml(str) {
  if (!str) return "";
  return String(str)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

