/* -------------------------------- Markup board (photo/map + pins) -------------------------------- */
/* Uses a <label>-wrapped file input (not a hidden ref+click()) so the picker only ever opens when the
   upload control itself is tapped — never when the map/photo is tapped to place a pin. Tapping near an
   existing pin toggles it off; tapping elsewhere adds a new pin of the active type. */

const hiddenFileInputStyle = {
  position: "absolute", width: 1, height: 1, padding: 0, margin: -1, overflow: "hidden",
  clip: "rect(0,0,0,0)", whiteSpace: "nowrap", border: 0,
};

function UploadLabel({ onFile, busy, children }) {
  return (
    <label style={{
      width: "100%", padding: "13px 0", borderRadius: 10, cursor: busy ? "default" : "pointer",
      background: C.bgInput, border: `1.5px dashed ${C.teal}`, color: C.primary,
      fontFamily: "Oswald, sans-serif", fontWeight: 600, letterSpacing: "0.03em", fontSize: 13.5,
      textTransform: "uppercase", display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
      boxSizing: "border-box",
    }}>
      <Camera size={16} /> {children}
      <input type="file" accept="image/*" disabled={busy} onChange={onFile} style={hiddenFileInputStyle} />
    </label>
  );
}

function ReplaceLabel({ onFile, busy }) {
  return (
    <label style={{
      flex: 1, padding: "9px 0", borderRadius: 8, cursor: busy ? "default" : "pointer",
      background: "none", border: `1px solid ${C.borderIdle}`, color: C.gray,
      fontFamily: "Inter, sans-serif", fontSize: 12.5, textAlign: "center", position: "relative",
    }}>
      {busy ? "Processing..." : "Replace Photo"}
      <input type="file" accept="image/*" disabled={busy} onChange={onFile} style={hiddenFileInputStyle} />
    </label>
  );
}

function distancePct(ax, ay, bx, by) {
  return Math.sqrt((ax - bx) ** 2 + (ay - by) ** 2);
}

function MarkupBoard({ image, markers, onAdd, onRemove, onUpload, pinTypes, activeType, setActiveType, hintText, readOnly }) {
  const containerRef = useRef(null);
  const [busy, setBusy] = useState(false);

  const handleFile = async (e) => {
    const file = e.target.files?.[0];
    e.target.value = "";
    if (!file) return;
    setBusy(true);
    try {
      const dataUrl = await resizeImageFile(file);
      onUpload(dataUrl);
    } catch (err) {
      console.error(err);
    } finally {
      setBusy(false);
    }
  };

  const handleClick = (e) => {
    if (readOnly || !containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const xPct = ((e.clientX - rect.left) / rect.width) * 100;
    const yPct = ((e.clientY - rect.top) / rect.height) * 100;
    // Toggle: tapping within ~3.5% of an existing pin removes it instead of adding a new one.
    const near = markers.find((m) => distancePct(m.xPct, m.yPct, xPct, yPct) < 3.5);
    if (near) {
      onRemove(near.id);
      return;
    }
    onAdd(activeType, Math.min(99, Math.max(1, xPct)), Math.min(99, Math.max(1, yPct)));
  };

  if (!image) {
    if (readOnly) return null;
    return <UploadLabel onFile={handleFile} busy={busy}>{busy ? "Processing..." : "Add Photo / Map"}</UploadLabel>;
  }

  return (
    <div>
      {!readOnly && pinTypes.length > 1 && (
        <div style={{ display: "flex", gap: 8, marginBottom: 10 }}>
          {pinTypes.map((pt) => (
            <button key={pt.key} type="button" onClick={() => setActiveType(pt.key)} style={{
              flex: 1, padding: "9px 0", borderRadius: 8, cursor: "pointer",
              border: `1.5px solid ${activeType === pt.key ? pt.color : C.borderIdle}`,
              background: activeType === pt.key ? pt.color + "1F" : C.bgInput,
              color: activeType === pt.key ? pt.color : C.gray,
              fontFamily: "Oswald, sans-serif", fontWeight: 600, fontSize: 12, letterSpacing: "0.03em", textTransform: "uppercase",
              display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
            }}>
              <span style={{ width: 8, height: 8, borderRadius: "50%", background: pt.color, display: "inline-block", flexShrink: 0 }} />
              {pt.label}
            </button>
          ))}
        </div>
      )}
      <div ref={containerRef} onClick={handleClick} style={{
        position: "relative", width: "100%", borderRadius: 10, overflow: "hidden",
        border: `1px solid ${C.borderIdle}`, cursor: readOnly ? "default" : "crosshair", lineHeight: 0,
      }}>
        <img src={image} alt="" draggable={false} style={{ width: "100%", display: "block", pointerEvents: "none", userSelect: "none" }} />
        {markers.map((m) => {
          const pt = pinTypes.find((p) => p.key === m.type) || pinTypes[0];
          return (
            <div key={m.id}
              style={{ position: "absolute", left: `${m.xPct}%`, top: `${m.yPct}%`, transform: "translate(-50%, -95%)", pointerEvents: "none" }}>
              <MapPin size={24} color={pt.color} fill={pt.color} strokeWidth={1.5}
                style={{ filter: "drop-shadow(0 1px 3px rgba(0,0,0,0.6))" }} />
            </div>
          );
        })}
      </div>
      {!readOnly && (
        <>
          {hintText && <div style={{ fontSize: 12, color: C.grayDim, marginTop: 6, fontFamily: "Inter, sans-serif" }}>{hintText}</div>}
          <div style={{ display: "flex", gap: 8, marginTop: 8 }}>
            <ReplaceLabel onFile={handleFile} busy={busy} />
          </div>
        </>
      )}
    </div>
  );
}

